"use client";

import { useMemo } from "react";
import { cva } from "class-variance-authority";
import { cn } from "@/lib/utils";
import { useLocale } from "@/lib/i18n";
import { computeLayout } from "./mn-workflow-orchestrator.layout";
import { EdgesLayer, ParticlesLayer, NodeGroup, PhaseBar } from "./mn-workflow-orchestrator.helpers";
import type {
  MnWorkflowOrchestratorProps,
} from "./mn-workflow-orchestrator.types";

export const workflowWrap = cva("relative w-full overflow-hidden rounded-md", {
  variants: {
    size: {
      sm: "max-w-sm",
      md: "max-w-xl",
      lg: "max-w-4xl",
      fluid: "w-full",
    },
  },
  defaultVariants: { size: "fluid" },
});

const SVG_W = 600;
const SVG_H = 400;
const NODE_R = 24;

export function MnWorkflowOrchestrator({
  nodes,
  edges,
  layout = "circular",
  phase,
  onNodeClick,
  onEdgeClick,
  selectedNode,
  ariaLabel,
  showParticles = true,
  animationSpeed = 1,
  size,
  className,
  ...rest
}: MnWorkflowOrchestratorProps) {
  const t = useLocale("workflowOrchestrator");

  const positions = useMemo(
    () => computeLayout(layout, nodes, edges, SVG_W, SVG_H),
    [layout, nodes, edges],
  );

  const particleDur = `${1.5 / animationSpeed}s`;

  if (nodes.length === 0) {
    return (
      <div className={cn(workflowWrap({ size }), className)} {...rest}>
        <p className="p-4 text-sm text-[var(--mn-text-muted)]">{t.noNodes}</p>
      </div>
    );
  }

  return (
    <div className={cn(workflowWrap({ size }), className)} {...rest}>
      <svg
        viewBox={`0 0 ${SVG_W} ${SVG_H}`}
        className="w-full h-auto"
        role="img"
        aria-label={ariaLabel ?? t.workflowVisualization}
      >
        <defs>
          <marker id="wfo-arrow" viewBox="0 0 10 10" refX="10" refY="5" markerWidth="6" markerHeight="6" orient="auto-start-reverse">
            <path d="M0,0 L10,5 L0,10 z" fill="var(--mn-text-muted)" />
          </marker>
          <style>{`
            @keyframes wfo-pulse { 0%,100% { r: ${NODE_R + 4}; opacity: .4 } 50% { r: ${NODE_R + 12}; opacity: 0 } }
            @keyframes wfo-think { 0%,100% { opacity: 1 } 50% { opacity: .3 } }
          `}</style>
          {edges.map((e) => {
            const a = positions.get(e.from);
            const b = positions.get(e.to);
            if (!a || !b) return null;
            return <path key={`p-${e.from}-${e.to}`} id={`wfo-path-${e.from}-${e.to}`} d={`M${a.x},${a.y} L${b.x},${b.y}`} />;
          })}
        </defs>

        <EdgesLayer edges={edges} positions={positions} onEdgeClick={onEdgeClick} />

        {showParticles && <ParticlesLayer edges={edges} positions={positions} dur={particleDur} />}

        {nodes.map((node) => {
          const pos = positions.get(node.id);
          if (!pos) return null;
          return (
            <NodeGroup
              key={node.id}
              node={node}
              pos={pos}
              selected={selectedNode === node.id}
              onClick={onNodeClick ? () => onNodeClick(node.id) : undefined}
            />
          );
        })}
      </svg>

      {phase && <PhaseBar phase={phase} label={t.phase} />}
    </div>
  );
}

"use client";

import type { WorkflowNode, WorkflowEdge, WorkflowPhase, LayoutPosition } from "./mn-workflow-orchestrator.types";

const NODE_R = 24;

/* ── Edges ── */

export function EdgesLayer({ edges, positions, onEdgeClick }: {
  edges: WorkflowEdge[];
  positions: Map<string, LayoutPosition>;
  onEdgeClick?: (from: string, to: string) => void;
}) {
  return (
    <g>
      {edges.map((e) => {
        const a = positions.get(e.from);
        const b = positions.get(e.to);
        if (!a || !b) return null;
        const directed = e.directed !== false;
        return (
          <line
            key={`e-${e.from}-${e.to}`}
            x1={a.x} y1={a.y} x2={b.x} y2={b.y}
            stroke={e.active ? "var(--mn-accent)" : "var(--mn-border-subtle)"}
            strokeWidth={e.active ? 2 : 1}
            strokeDasharray={e.active ? "none" : "4 4"}
            markerEnd={directed ? "url(#wfo-arrow)" : undefined}
            markerStart={e.bidirectional ? "url(#wfo-arrow)" : undefined}
            className="transition-all duration-500"
            style={{ cursor: onEdgeClick ? "pointer" : undefined }}
            onClick={onEdgeClick ? () => onEdgeClick(e.from, e.to) : undefined}
          />
        );
      })}
      {edges.filter((e) => e.label).map((e) => {
        const a = positions.get(e.from);
        const b = positions.get(e.to);
        if (!a || !b) return null;
        return (
          <text
            key={`el-${e.from}-${e.to}`}
            x={(a.x + b.x) / 2} y={(a.y + b.y) / 2 - 6}
            textAnchor="middle"
            className="text-[8px] fill-[var(--mn-text-tertiary)]"
          >
            {e.label}
          </text>
        );
      })}
    </g>
  );
}

/* ── Particles ── */

export function ParticlesLayer({ edges, positions, dur }: {
  edges: WorkflowEdge[];
  positions: Map<string, LayoutPosition>;
  dur: string;
}) {
  return (
    <g>
      {edges.filter((e) => e.active).map((e) => {
        const a = positions.get(e.from);
        const b = positions.get(e.to);
        if (!a || !b) return null;
        return (
          <circle key={`pt-${e.from}-${e.to}`} r="3" fill="var(--mn-accent)" opacity="0.8">
            <animateMotion dur={dur} repeatCount="indefinite">
              <mpath xlinkHref={`#wfo-path-${e.from}-${e.to}`} />
            </animateMotion>
          </circle>
        );
      })}
    </g>
  );
}

/* ── Node ── */

function statusFill(node: WorkflowNode): string {
  const color = node.color ?? "var(--mn-accent)";
  const s = node.status ?? "idle";
  if (s === "active") return `${color}30`;
  if (s === "done") return `${color}15`;
  if (s === "error") return "var(--mn-error-bg)";
  return "var(--mn-surface-raised)";
}

function statusStroke(node: WorkflowNode): string {
  const s = node.status ?? "idle";
  if (s === "idle") return "var(--mn-border)";
  return node.color ?? statusColor(s);
}

function statusColor(status: string): string {
  const map: Record<string, string> = {
    active: "var(--mn-accent)", thinking: "var(--mn-warning)",
    done: "var(--mn-success)", error: "var(--mn-error)",
  };
  return map[status] ?? "var(--mn-text-muted)";
}

export function NodeGroup({ node, pos, selected, onClick }: {
  node: WorkflowNode;
  pos: LayoutPosition;
  selected?: boolean;
  onClick?: () => void;
}) {
  const isActive = node.status === "active";
  const isThinking = node.status === "thinking";
  const isDone = node.status === "done";
  const isError = node.status === "error";
  const sc = statusColor(node.status ?? "idle");

  return (
    <g style={{ cursor: onClick ? "pointer" : "default" }} onClick={onClick} role={onClick ? "button" : undefined} tabIndex={onClick ? 0 : undefined}>
      {isActive && (
        <circle cx={pos.x} cy={pos.y} r={NODE_R + 4} fill="none" stroke={sc} strokeWidth="2" style={{ animation: "wfo-pulse 1.5s ease-in-out infinite" }} />
      )}

      {selected && (
        <circle cx={pos.x} cy={pos.y} r={NODE_R + 6} fill="none" stroke="var(--mn-accent)" strokeWidth="2" strokeDasharray="4 2" />
      )}

      <circle
        cx={pos.x} cy={pos.y} r={NODE_R}
        fill={statusFill(node)}
        stroke={statusStroke(node)}
        strokeWidth={isActive || selected ? 2.5 : 1.5}
        className="transition-all duration-300"
      />

      {node.icon && (
        <text x={pos.x} y={pos.y + 5} textAnchor="middle" className="text-[14px] fill-[var(--mn-text)]" style={{ fontFamily: "system-ui" }}>
          {node.icon.charAt(0)}
        </text>
      )}

      <text x={pos.x} y={pos.y + NODE_R + 14} textAnchor="middle" className="text-[10px] font-medium fill-[var(--mn-text)]">
        {node.label}
      </text>

      {node.sublabel && (
        <text x={pos.x} y={pos.y + NODE_R + 25} textAnchor="middle" className="text-[8px] fill-[var(--mn-text-tertiary)]">
          {node.sublabel}
        </text>
      )}

      {(isActive || isThinking || isDone || isError) && (
        <circle
          cx={pos.x + 16} cy={pos.y - 16} r="5"
          fill={sc}
          stroke="var(--mn-surface)"
          strokeWidth="2"
          style={isThinking ? { animation: "wfo-think 0.8s ease-in-out infinite" } : undefined}
        />
      )}

      {node.badge && (
        <g>
          <rect x={pos.x + 10} y={pos.y - NODE_R - 8} width={node.badge.length * 7 + 6} height="14" rx="7" fill="var(--mn-accent)" />
          <text x={pos.x + 13 + (node.badge.length * 3.5)} y={pos.y - NODE_R + 2} textAnchor="middle" className="text-[8px] font-bold fill-[var(--mn-accent-text)]">{node.badge}</text>
        </g>
      )}
    </g>
  );
}

/* ── Phase bar ── */

export function PhaseBar({ phase, label }: { phase: WorkflowPhase; label: string }) {
  const pct = phase.total > 0 ? (phase.current / phase.total) * 100 : 0;
  return (
    <div className="flex items-center gap-3 px-3 py-2 text-xs text-[var(--mn-text-muted)]">
      <span className="font-medium">{label} {phase.current}/{phase.total}</span>
      <div className="flex-1 h-1.5 rounded-full bg-[var(--mn-surface-sunken)]">
        <div className="h-full rounded-full bg-[var(--mn-accent)] transition-all duration-500" style={{ width: `${pct}%` }} />
      </div>
      {phase.label && <span>{phase.label}</span>}
      {phase.agent && <span className="font-semibold text-[var(--mn-text)]">{phase.agent}</span>}
    </div>
  );
}

import type { WorkflowNode, WorkflowEdge, LayoutPosition, WorkflowLayout } from "./mn-workflow-orchestrator.types";

const TWO_PI = Math.PI * 2;

/* ── Circular ── */

function circularLayout(nodes: WorkflowNode[], _edges: WorkflowEdge[], w: number, h: number): Map<string, LayoutPosition> {
  const cx = w / 2;
  const cy = h / 2;
  const r = Math.min(cx, cy) * 0.65;
  const positions = new Map<string, LayoutPosition>();
  const count = nodes.length;
  if (count === 0) return positions;
  if (count === 1) {
    positions.set(nodes[0].id, { x: cx, y: cy });
    return positions;
  }
  for (let i = 0; i < count; i++) {
    const angle = (TWO_PI * i) / count - Math.PI / 2;
    positions.set(nodes[i].id, {
      x: cx + r * Math.cos(angle),
      y: cy + r * Math.sin(angle),
    });
  }
  return positions;
}

/* ── Horizontal pipeline ── */

function horizontalLayout(nodes: WorkflowNode[], edges: WorkflowEdge[], w: number, h: number): Map<string, LayoutPosition> {
  const sorted = topoSort(nodes, edges);
  const positions = new Map<string, LayoutPosition>();
  const count = sorted.length;
  if (count === 0) return positions;
  const padX = w * 0.1;
  const stepX = count > 1 ? (w - padX * 2) / (count - 1) : 0;
  for (let i = 0; i < count; i++) {
    positions.set(sorted[i], { x: padX + stepX * i, y: h / 2 });
  }
  return positions;
}

/* ── Vertical flow ── */

function verticalLayout(nodes: WorkflowNode[], edges: WorkflowEdge[], w: number, h: number): Map<string, LayoutPosition> {
  const sorted = topoSort(nodes, edges);
  const positions = new Map<string, LayoutPosition>();
  const count = sorted.length;
  if (count === 0) return positions;
  const padY = h * 0.1;
  const stepY = count > 1 ? (h - padY * 2) / (count - 1) : 0;
  for (let i = 0; i < count; i++) {
    positions.set(sorted[i], { x: w / 2, y: padY + stepY * i });
  }
  return positions;
}

/* ── Auto (simple force-directed) ── */

function autoLayout(nodes: WorkflowNode[], edges: WorkflowEdge[], w: number, h: number): Map<string, LayoutPosition> {
  if (nodes.length === 0) return new Map();
  // Seed with circular positions
  const positions = circularLayout(nodes, edges, w, h);
  const edgeSet = edges.map((e) => [e.from, e.to] as const);
  const repulsion = 3000;
  const attraction = 0.005;
  const damping = 0.9;
  const vel = new Map<string, { vx: number; vy: number }>();
  for (const n of nodes) vel.set(n.id, { vx: 0, vy: 0 });

  for (let iter = 0; iter < 60; iter++) {
    // Repulsion between all pairs
    for (let i = 0; i < nodes.length; i++) {
      for (let j = i + 1; j < nodes.length; j++) {
        const a = positions.get(nodes[i].id)!;
        const b = positions.get(nodes[j].id)!;
        const dx = a.x - b.x;
        const dy = a.y - b.y;
        const dist = Math.max(Math.sqrt(dx * dx + dy * dy), 1);
        const force = repulsion / (dist * dist);
        const fx = (dx / dist) * force;
        const fy = (dy / dist) * force;
        vel.get(nodes[i].id)!.vx += fx;
        vel.get(nodes[i].id)!.vy += fy;
        vel.get(nodes[j].id)!.vx -= fx;
        vel.get(nodes[j].id)!.vy -= fy;
      }
    }
    // Attraction along edges
    for (const [from, to] of edgeSet) {
      const a = positions.get(from);
      const b = positions.get(to);
      if (!a || !b) continue;
      const dx = b.x - a.x;
      const dy = b.y - a.y;
      const fx = dx * attraction;
      const fy = dy * attraction;
      vel.get(from)!.vx += fx;
      vel.get(from)!.vy += fy;
      vel.get(to)!.vx -= fx;
      vel.get(to)!.vy -= fy;
    }
    // Apply velocities
    for (const n of nodes) {
      const v = vel.get(n.id)!;
      const p = positions.get(n.id)!;
      p.x = Math.max(40, Math.min(w - 40, p.x + v.vx));
      p.y = Math.max(40, Math.min(h - 40, p.y + v.vy));
      v.vx *= damping;
      v.vy *= damping;
    }
  }
  return positions;
}

/* ── Topological sort (for pipeline layouts) ── */

function topoSort(nodes: WorkflowNode[], edges: WorkflowEdge[]): string[] {
  const ids = new Set(nodes.map((n) => n.id));
  const adj = new Map<string, string[]>();
  const inDeg = new Map<string, number>();
  for (const id of ids) { adj.set(id, []); inDeg.set(id, 0); }
  for (const e of edges) {
    if (ids.has(e.from) && ids.has(e.to)) {
      adj.get(e.from)!.push(e.to);
      inDeg.set(e.to, (inDeg.get(e.to) ?? 0) + 1);
    }
  }
  const queue = [...ids].filter((id) => (inDeg.get(id) ?? 0) === 0);
  const result: string[] = [];
  while (queue.length > 0) {
    const cur = queue.shift()!;
    result.push(cur);
    for (const next of adj.get(cur) ?? []) {
      const d = (inDeg.get(next) ?? 1) - 1;
      inDeg.set(next, d);
      if (d === 0) queue.push(next);
    }
  }
  // Append any nodes missed by cycles
  for (const id of ids) {
    if (!result.includes(id)) result.push(id);
  }
  return result;
}

/* ── Public API ── */

export function computeLayout(
  layout: WorkflowLayout,
  nodes: WorkflowNode[],
  edges: WorkflowEdge[],
  width: number,
  height: number,
): Map<string, LayoutPosition> {
  switch (layout) {
    case "circular": return circularLayout(nodes, edges, width, height);
    case "horizontal": return horizontalLayout(nodes, edges, width, height);
    case "vertical": return verticalLayout(nodes, edges, width, height);
    case "auto": return autoLayout(nodes, edges, width, height);
  }
}

import type { VariantProps } from "class-variance-authority";
import type { workflowWrap } from "./mn-workflow-orchestrator";

/* ── Node ── */

export type WorkflowNodeStatus =
  | "idle"
  | "active"
  | "thinking"
  | "done"
  | "error";

export interface WorkflowNode {
  id: string;
  label: string;
  /** Lucide icon name (e.g. "Users", "Shield"). Rendered via dynamic import. */
  icon?: string;
  /** Hex color or CSS var for the node accent. Falls back to --mn-accent. */
  color?: string;
  status?: WorkflowNodeStatus;
  /** Secondary text below the label. */
  sublabel?: string;
  /** Small badge text (e.g. "3", "OK"). */
  badge?: string;
  /** Grouping key for cluster rendering. */
  group?: string;
}

/* ── Edge ── */

export interface WorkflowEdge {
  from: string;
  to: string;
  /** Show an arrowhead at the target end. @default true */
  directed?: boolean;
  /** Label on the edge midpoint. */
  label?: string;
  /** Whether the edge is currently active (shows particles). */
  active?: boolean;
  /** If true, render arrows in both directions. */
  bidirectional?: boolean;
}

/* ── Phase indicator ── */

export interface WorkflowPhase {
  current: number;
  total: number;
  label?: string;
  agent?: string;
}

/* ── Layout ── */

export type WorkflowLayout =
  | "circular"
  | "horizontal"
  | "vertical"
  | "auto";

export interface LayoutPosition {
  x: number;
  y: number;
}

/* ── Component props ── */

export interface MnWorkflowOrchestratorProps
  extends Omit<React.HTMLAttributes<HTMLDivElement>, "children">,
    VariantProps<typeof workflowWrap> {
  nodes: WorkflowNode[];
  edges: WorkflowEdge[];
  layout?: WorkflowLayout;
  /** Show the phase progress bar. */
  phase?: WorkflowPhase;
  /** Callback when a node is clicked. */
  onNodeClick?: (nodeId: string) => void;
  /** Callback when an edge is clicked. */
  onEdgeClick?: (from: string, to: string) => void;
  /** Highlight a specific node. */
  selectedNode?: string;
  /** Accessible label for the SVG. */
  ariaLabel?: string;
  /** Show animated particles on active edges. @default true */
  showParticles?: boolean;
  /** Animation speed multiplier. @default 1 */
  animationSpeed?: number;
}
